var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장, 여기가 정말 알렌 선생님이 사는 곳 맞아?","JPN":"会長、本当にここがアレン先生の家なの？","ENG":"So, Yen, is this really where Mr. Birmingham lives?","TWN":"會長，艾倫老師真的住在這裡沒錯嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 알렌 선생님과 함께 퇴근한 적 있는 교직원 분들에게도 확인 받았어요.","JPN":"はい、アレン先生と一緒に退勤したことがある職員の方にも確認いただきました。","ENG":"Yes. I even confirmed it with a faculty member who used to share a commute with him.","TWN":"是的，我們有和曾經跟艾倫老師一起下班的教職員確認過。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음, 난 원룸에만 살아 봐서 잘 모르겠는데…….","JPN":"ううん、私はワンルームでしか暮らしたことがないからよくわからないけど……","ENG":"Hmm, I've only lived in a hole in the wall so I wouldn't know…","TWN":"嗯，我只住過套房所以不太清楚……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알렌 선생님이 혹시 엄청난 부자인 거 아냐?","JPN":"アレン先生って、もしかしたらとんでもないお金持ちなのかな？","ENG":"But could it be because Mr. Birmingham's super rich?","TWN":"請問艾倫老師是大富翁嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 숲이 부자들의 개인용 사냥터 같은 곳일 수도 있잖아.","JPN":"この森がお金持ちの個人用狩猟場みたいな場所かもしれないでしょ。","ENG":"This forest might be just a private hunting ground for rich folks.","TWN":"這片森林你說是有錢人專屬的狩獵場我也相信啊！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아무리 부자라고 해도, 도심 인근에 이런 국립공원 규모의 사유지를 보유하긴 어려워요.","JPN":"いくら大富豪とはいえ、都心近辺でこのような\\n国立公園規模の私有地を保有するのは不可能でしょう。","ENG":"Even the most affluent person would have trouble maintaining such an expanse of nature so close to the city.","TWN":"再怎麼有錢，也很難在市中心擁有像這樣如國家公園般的私人土地。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무엇보다 이 숲은 도시 관리국이 제공하는 지도에도 나와 있지 않아요.","JPN":"何より、この森は都市管理局が提供する地図に載っていません。","ENG":"Most of all, this forest doesn't appear on the maps provided by the City Management.","TWN":"更何況，這片森林並沒有出現在城市管理局提供的地圖上。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지형 정보를 분석하려고 했지만, 데이터베이스에 대조군이 없다고 하더군요.","JPN":"地形情報を分析しようとしましたが、データベースにないようです。","ENG":"We tried to analyze the terrain, but the database could not find any comparable matches.","TWN":"原本是想分析地形資料的，但資料庫中沒有對照組。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……확실히, 수상하네.","JPN":"……確かに怪しいね。","ENG":"That definitely sounds fishy…","TWN":"果然……很可疑！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"수상한 건 그게 다가 아니야!","JPN":"怪しいのはそれだけじゃないの！","ENG":"That's not all!","TWN":"可疑的地方不只是這樣而已！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아까 그 침식체들도 그래. 우리가 여기 오자마자 갑자기 공격해 왔거든.","JPN":"さっきの侵食体もそう。私たちがここに着いた途端、いきなり襲いかかってきたの。","ENG":"Remember those C.O.s? They attacked us as soon as we got here.","TWN":"剛剛那些侵蝕體也是，我們一抵達這裡就突然來攻擊我們。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 미카 넌 여기 왜 온 거야? 싸움은 싫어하지 않았어?","JPN":"そういえば、ミカはどうしてここに来たの？　戦闘は苦手なんじゃなかった？","ENG":"Come to think of it, what are you doing here, Mika? I thought you hated fighting.","TWN":"說到這個，米卡，你來這裡幹嘛？你不是討厭打打殺殺嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그게……. 학생 정보를 확인해 보니까 레이 선배 주소도 여기더라고.","JPN":"それが……生徒情報を照会したらレイ先輩の住所もここだったの。","ENG":"Well... According to the student database, Ray's home is registered to this address as well.","TWN":"因為……我查看學生資料後，發現雷伊前輩的地址也是在這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"레이 선배도?","JPN":"レイ先輩も？","ENG":"Even Ray?","TWN":"雷伊前輩也住這裡？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응. 혹시라도 무슨 오해가 있을지도 모르잖아.","JPN":"うん。もしかしたら何かの間違いかもしれないでしょ？","ENG":"Yeah. Maybe there's been some kind of mix-up.","TWN":"對，這當中可能有什麼誤會。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"레이 선배가 사람을 해쳤을 거라고는 도저히 믿기지 않아서……. 회장님을 따라 온 거야.","JPN":"レイ先輩が人を傷つけたなんてとても信じられなくて……だから会長についてきたの。","ENG":"I refuse to believe that Ray is capable of hurting anyone… So, I followed the President here.","TWN":"我不相信雷伊前輩會做出傷害的事……所以才跟著會長過來。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그랬구나…….","JPN":"そうだったんだ……","ENG":"I see…","TWN":"原來是這樣……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};